#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static void controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    /* Check if turbidity is stale */
    if (controller->has_valid_turbidity) {
        if ((now_ms - controller->last_turbidity_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller->has_valid_turbidity = false;
        }
    }

    /* Check if level is stale */
    if (controller->has_valid_level) {
        if ((now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller->has_valid_level = false;
        }
    }
}

static bool controller_check_safe_state(controller_t *controller, uint32_t now_ms)
{
    /* Must have both sensors valid to proceed */
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        return true;
    }

    return false;
}

static void controller_handle_complete_state(controller_t *controller, controller_output_t *output)
{
    /* If level is below threshold, stay in COMPLETE */
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller_set_safe_idle(controller);
        output->filter_on = false;
        output->drain_open = false;
        output->state = CONTROLLER_STATE_COMPLETE;
        return;
    }

    /* If level is back up, we need to re-evaluate */
    /* Reset clear streak and go to appropriate state based on turbidity */
    controller->clear_streak_count = 0;

    if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
        /* Go to FILTERING */
        controller->state = CONTROLLER_STATE_FILTERING;
        controller->filter_on = true;
        controller->drain_open = false;
    } else {
        /* Clear water, but need streak - stay in filtering until we get streak */
        controller->clear_streak_count = 1;  /* This sample counts as clear */
        if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
            controller->state = CONTROLLER_STATE_SETTLING;
            controller->settling_started_ms = controller->last_turbidity_ms;
            controller->filter_on = false;
            controller->drain_open = false;
        } else {
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
        }
    }
}

static void controller_handle_filtering_state(controller_t *controller, 
                                               controller_input_t input,
                                               controller_output_t *output)
{
    /* Check for disturbance during draining that sends us back here */
    /* Already in filtering, just process new inputs */

    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* Cloudy - reset streak */
            controller->clear_streak_count = 0;
        } else {
            /* Clear - increment streak */
            controller->clear_streak_count++;

            if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
                controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                /* Transition to SETTLING */
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->settling_started_ms = input.now_ms;
                controller->filter_on = false;
                controller->drain_open = false;
                return;
            }
        }
    }

    /* Stay in FILTERING */
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->filter_on = true;
    controller->drain_open = false;
}

static void controller_handle_settling_state(controller_t *controller,
                                              controller_input_t input,
                                              controller_output_t *output)
{
    /* During settling, check for disturbance */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            /* Disturbance - go back to FILTERING */
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
            return;
        }
    }

    /* Check if settling is complete and we can drain */
    uint32_t settle_elapsed = input.now_ms - controller->settling_started_ms;

    if (settle_elapsed >= CONTROLLER_SETTLING_MS &&
        controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
        controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
        /* Transition to DRAINING */
        controller->state = CONTROLLER_STATE_DRAINING;
        controller->filter_on = false;
        controller->drain_open = true;
        return;
    }

    /* Stay in SETTLING */
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->filter_on = false;
    controller->drain_open = false;
}

static void controller_handle_draining_state(controller_t *controller,
                                              controller_input_t input,
                                              controller_output_t *output)
{
    /* Check for disturbance during draining */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Disturbance - close drain, start filtering */
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
            return;
        }
