    /* Check if level is stale */
    if (controller->has_valid_level) {
        if ((now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller->has_valid_level = false;
        }
    }
}

static bool controller_both_sensors_valid(const controller_t *controller)
{
    return controller->has_valid_turbidity && controller->has_valid_level;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle timeout and invalid inputs - go to safe state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.changed = (previous_filter_on != output.filter_on) ||
                         (previous_drain_open != output.drain_open) ||
                         (previous_state != output.state);
        return output;
    }

    /* Update sensor data based on input type */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }
    /* For CONTROLLER_INPUT_NONE, don't update sensor data */

    /* Check for sensor timeout - if either sensor is stale, go to safe state */
    controller_check_sensor_timeout(controller, input.now_ms);

    /* If we don't have both sensors valid, stay in safe idle */
    if (!controller_both_sensors_valid(controller)) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        output.changed = (previous_filter_on != output.filter_on) ||
                         (previous_drain_open != output.drain_open) ||
                         (previous_state != output.state);
        return output;
    }

    /* Now we have both sensors valid - run the state machine */

    /* Check for COMPLETE condition (level too low for any operation) */
    if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
        controller->state = CONTROLLER_STATE_COMPLETE;
        controller->filter_on = false;
        controller->drain_open = false;
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_COMPLETE;
        output.state_name = controller_state_name(CONTROLLER_STATE_COMPLETE);
        output.changed = (previous_filter_on != output.filter_on) ||
                         (previous_drain_open != output.drain_open) ||
                         (previous_state != output.state);
        return output;
    }

    /* Level is sufficient for processing - run state machine */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Just got both sensors valid - evaluate initial state based on turbidity */
        if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* Cloudy water - start filtering */
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
        } else {
            /* Clear water - count this as first clear sample */
            controller->clear_streak_count = 1;
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                /* Already have enough clear samples - go to settling */
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->settling_started_ms = input.now_ms;
                controller->filter_on = false;
                controller->drain_open = false;
            } else {
                /* Need more clear samples - start filtering first */
                controller->state = CONTROLLER_STATE_FILTERING;
                controller->filter_on = true;
                controller->drain_open = false;
            }
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Check for disturbance that resets streak */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                /* Still cloudy - reset streak */
                controller->clear_streak_count = 0;
            } else {
                /* Clear sample - increment streak */
                controller->clear_streak_count++;

                if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
                    controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                    /* Enough clear samples - transition to SETTLING */
                    controller->state = CONTROLLER_STATE_SETTLING;
                    controller->settling_started_ms = input.now_ms;
                    controller->filter_on = false;
                    controller->drain_open = false;
                    break;
                }
            }
        }
        /* Stay in FILTERING */
        controller->state = CONTROLLER_STATE_FILTERING;
        controller->filter_on = true;
        controller->drain_open = false;
        break;

    case CONTROLLER_STATE_SETTLING:
        /* Check for disturbance during settling */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                /* Disturbance - go back to FILTERING */
                controller->state = CONTROLLER_STATE_FILTERING;
                controller->clear_streak_count = 0;
                controller->filter_on = true;
                controller->drain_open = false;
                break;
            }
        }

        /* Check if settling period has elapsed and we can drain */
        uint32_t settle_elapsed = input.now_ms - controller->settling_started_ms;
        if (settle_elapsed >= CONTROLLER_SETTLING_MS &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL &&
            controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* Transition to DRAINING */
            controller->state = CONTROLLER_STATE_DRAINING;
            controller->filter_on = false;
            controller->drain_open = true;
            break;
        }

        /* Stay in SETTLING */
        controller->state = CONTROLLER_STATE_SETTLING;
        controller->filter_on = false;
        controller->drain_open = false;
        break;

    case CONTROLLER_STATE_DRAINING:
        /* Check for disturbance during draining */
        if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
            if (controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Disturbance - close drain, start filtering */
                controller->state = CONTROLLER_STATE_FILTERING;
                controller->clear_streak_count = 0;
                controller->filter_on = true;
                controller->drain_open = false;
                break;
            }
        }

        /* Check if tank is empty */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
            break;
        }

        /* Stay in DRAINING */
        controller->state = CONTROLLER_STATE_DRAINING;
        controller->filter_on = false;
        controller->drain_open = true;
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* If level is still low, stay in COMPLETE */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
            break;
        }

        /* Level is back up - re-evaluate based on turbidity */
        controller->clear_streak_count = 0;
        if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
            /* Cloudy - go to FILTERING */
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
        } else {
            /* Clear - start counting streak */
            controller->clear_streak_count = 1;
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->settling_started_ms = input.now_ms;
                controller->filter_on = false;
                controller->drain_open = false;
            } else {
                controller->state = CONTROLLER_STATE_FILTERING;
                controller->filter_on = true;
                controller->drain_open = false;
            }
        }
        break;

    default:
        /* Unknown state - go to safe idle */
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
                     (previous_drain_open != controller->drain_open) ||
                     (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

